-- {"operators": "INNER_JOIN,AGGREGATE,UNION,CTE,SUBQUERY", "complexity": "high", "is_incremental": true, "has_nulls": false, "has_cast": false, "has_case": false, "tables": "WAREHOUSE,OORDER,ORDER_LINE", "ducklake": true}
WITH sales_by_w AS (SELECT ol.OL_W_ID AS w, SUM(ol.OL_AMOUNT) AS total FROM dl.ORDER_LINE ol JOIN dl.OORDER o ON ol.OL_W_ID = o.O_W_ID AND ol.OL_D_ID = o.O_D_ID AND ol.OL_O_ID = o.O_ID GROUP BY ol.OL_W_ID), ytd_by_w AS (SELECT W_ID AS w, W_YTD AS total FROM dl.WAREHOUSE) SELECT w, total, 'sales' AS kind FROM sales_by_w UNION ALL SELECT w, total, 'ytd' FROM ytd_by_w;
